const items = $input.first().json.items || [];
const today = new Date().toISOString().split('T')[0];

const videos = items.map((v, i) => {
  const s = v.snippet;
  const st = v.statistics;
  return {
    video_id: v.id,
    title: s.title,
    published_at: s.publishedAt.split('T')[0],
    views: parseInt(st.viewCount || '0'),
    likes: parseInt(st.likeCount || '0'),
    comments: parseInt(st.commentCount || '0'),
    snapshot_date: today,
    position: i + 1
  };
});

// Build Telegram message
const totalViews = videos.reduce((s, v) => s + v.views, 0);
const totalLikes = videos.reduce((s, v) => s + v.likes, 0);

let msg = `📊 Daily Video Report — ${today}\n\n`;
msg += `Channel: ${videos.length} videos | ${totalViews.toLocaleString()} total views\n\n`;

// Sort by views descending
const sorted = [...videos].sort((a, b) => b.views - a.views);

for (const v of sorted.slice(0, 10)) {
  const daysOld = Math.floor((Date.now() - new Date(v.published_at).getTime()) / 86400000);
  const isNew = daysOld <= 2;
  msg += `${isNew ? '⭐ ' : ''}${v.title.slice(0, 50)}\n`;
  msg += `  👀 ${v.views.toLocaleString()} | 👍 ${v.likes} | 💬 ${v.comments}`;
  msg += ` | ${daysOld}d old\n\n`;
}

return [{ json: { message: msg, videos } }];
